const tokenData = $input.first().json;

// Extraer el access token y refresh token
return [{
  json: {
    access_token: tokenData.access_token,
    refresh_token: tokenData.refresh_token,
    token_type: tokenData.token_type,
    expires_in: tokenData.expires_in
  }
}];

const userId = $input.first().json.id;
const accessToken = $('Extract_Token').first().json.access_token;

const ITEMS_PER_PAGE = 100;
const DELAY_MS = 500;
let allItems = [];
let offset = 0;
let hasMorePages = true;
let pageNumber = 1;

console.log(`Iniciando paginación de items para user: ${userId}`);

async function getPage(offset) {
  const url = `https://api.mercadolibre.com/users/${userId}/items/search?status=active&offset=${offset}&limit=${ITEMS_PER_PAGE}`;

  try {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: url,
      headers: {
        'Authorization': `Bearer ${accessToken}`
      },
      json: true
    });
    return response;
  } catch (error) {
    console.error(`❌ Error: ${error.message}`);
    throw error;
  }
}

while (hasMorePages) {
  console.log(`📄 Página ${pageNumber}: offset=${offset}`);

  const pageData = await getPage.call(this, offset);
  const results = pageData.results || [];

  console.log(`✅ ${results.length} items | Total: ${allItems.length + results.length}`);

  allItems = allItems.concat(results);

  const totalItems = pageData.paging ? pageData.paging.total : 0;

  if (results.length < ITEMS_PER_PAGE || allItems.length >= totalItems) {
    hasMorePages = false;
    console.log(`🎉 Completo: ${allItems.length} items`);
  } else {
    offset += ITEMS_PER_PAGE;
    pageNumber++;
    await new Promise(resolve => setTimeout(resolve, DELAY_MS));
  }
}

console.log(`✨ Total: ${allItems.length} items en ${pageNumber} páginas`);

return allItems.map(itemId => ({
  json: {
    item_id: itemId
  }
}));

const userId = $input.first().json.id;
const accessToken = $('Extract_Token').first().json.access_token;

const ORDERS_PER_PAGE = 50;
const DELAY_MS = 0;
let allOrders = [];
let offset = 0;
let hasMorePages = true;
let pageNumber = 1;

console.log(`Iniciando paginación de órdenes para user: ${userId}`);

const now = new Date();
const sixtyDaysAgo = new Date(now - 60 * 24 * 60 * 60 * 1000);
const dateFrom = sixtyDaysAgo.toISOString();
const dateTo = now.toISOString();

console.log(`📅 Rango: ${dateFrom} a ${dateTo}`);

async function getOrdersPage(offset) {
  const url = `https://api.mercadolibre.com/orders/search?seller=${userId}&order.date_created.from=${dateFrom}&order.date_created.to=${dateTo}&offset=${offset}&limit=${ORDERS_PER_PAGE}`;

  try {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: url,
      headers: {
        'Authorization': `Bearer ${accessToken}`
      },
      json: true
    });
    return response;
  } catch (error) {
    console.error(`❌ Error: ${error.message}`);
    throw error;
  }
}

while (hasMorePages) {
  console.log(`📄 Página ${pageNumber}: offset=${offset}`);

  const pageData = await getOrdersPage.call(this, offset);
  const results = pageData.results || [];

  console.log(`✅ ${results.length} órdenes | Total: ${allOrders.length + results.length}`);

  allOrders = allOrders.concat(results);

  const totalOrders = pageData.paging ? pageData.paging.total : 0;

  if (results.length < ORDERS_PER_PAGE || allOrders.length >= totalOrders) {
    hasMorePages = false;
    console.log(`🎉 Completo: ${allOrders.length} órdenes`);
  } else {
    offset += ORDERS_PER_PAGE;
    pageNumber++;
    await new Promise(resolve => setTimeout(resolve, DELAY_MS));
  }

  if (pageNumber > 200) {
    console.log(`⚠️ Límite de páginas alcanzado`);
    hasMorePages = false;
  }
}

console.log(`✨ Total: ${allOrders.length} órdenes en ${pageNumber} páginas`);

return [{
  json: {
    results: allOrders,
    paging: {
      total: allOrders.length,
      offset: 0,
      limit: allOrders.length
    }
  }
}];

// ========================================
// PASO 1: OBTENER Y SEPARAR DATOS
// ========================================
const mergedData = $input.all();
console.log(`📦 Total items recibidos del Merge: ${mergedData.length}`);

// Separar los datos de Get_Item_Details y Get_Sales_60d
let items = [];
let salesData = null;

mergedData.forEach(item => {
  const data = item.json;

  if (data.results && data.paging) {
    salesData = data;
  } else if (data.id && data.title) {
    items.push(item);
  }
});

if (!salesData) {
  salesData = $('Get_Sales_60d_Paginated').first().json;
}

console.log(`📦 Items de productos: ${items.length}`);
console.log(`📊 Órdenes: ${salesData.results ? salesData.results.length : 0}`);

const orders = salesData.results || [];

// ========================================
// PASO 2: CARGAR COSTOS DE PROVEEDORES
// ========================================
const providerData = $('Read_Provider_Costs').all();
console.log(`💰 Datos de proveedores: ${providerData.length} registros`);

// Función auxiliar para limpiar valores monetarios
function parsePrice(value) {
  if (!value) return 0;
  const cleaned = String(value).replace(/[$\s]/g, '').replace(/,/g, '');
  return parseFloat(cleaned) || 0;
}

// Crear mapa de costos por MLC ID y SKU
const costsByMLC = {};
const costsBySKU = {};

providerData.forEach(row => {
  const data = row.json;

  const mlcId = data['Número de publicación'] || data['numero_de_publicacion'];
  const sku = data['SKU'] || data['sku'];
  const proveedor = data['Proveedor'] || data['proveedor'];

  const costoFinal = parsePrice(data['Costo'] || data['costo']);

  let costo = costoFinal;
  if (costo === 0) {
    const precio = parsePrice(data['Precio'] || data['precio']);
    const comision = parseFloat(data['Comision %'] || data['comision'] || data['Convenio %'] || data['convenio'] || 0);
    costo = precio * (1 - comision);
  }

  const precioLista = parsePrice(data['Precio'] || data['precio']);

  if (mlcId && costo > 0) {
    costsByMLC[mlcId] = {
      proveedor: proveedor,
      costo: costo,
      precio_lista: precioLista
    };
  }

  if (sku && costo > 0) {
    costsBySKU[sku] = {
      proveedor: proveedor,
      costo: costo,
      precio_lista: precioLista
    };
  }
});

console.log(`💰 Costos mapeados - Por MLC: ${Object.keys(costsByMLC).length}, Por SKU: ${Object.keys(costsBySKU).length}`);

// ========================================
// PASO 3: FUNCIÓN EXTRAER SKU
// ========================================
function extractSKU(itemData) {
  if (itemData.attributes && Array.isArray(itemData.attributes)) {
    const skuAttr = itemData.attributes.find(attr => 
      attr.id === 'SELLER_SKU' && attr.value_name
    );

    if (skuAttr && skuAttr.value_name) {
      return skuAttr.value_name;
    }
  }

  return itemData.seller_custom_field || itemData.id;
}

// ========================================
// PASO 4: CALCULAR VENTAS POR SKU Y TIPO DE FULFILLMENT
// ========================================
const now = new Date();
const thirtyDaysAgo = new Date(now - 30 * 24 * 60 * 60 * 1000);
const salesBySKU = {};

console.log('📊 Procesando ventas por tipo de fulfillment...');

orders.forEach(order => {
  if (order.order_items) {
    order.order_items.forEach(item => {
      const sku = item.item.seller_sku || item.item.id;
      const orderDate = new Date(order.date_created);
      const quantity = item.quantity || 0;

      // CORRECCIÓN: Determinar si es FULL o FLEX basado en shipping_mode
      // me2 = MercadoEnvíos 2.0 = FULL
      const shippingMode = order.shipping ? order.shipping.shipping_mode : null;
      const isFull = shippingMode === 'me2';

      if (!salesBySKU[sku]) {
        salesBySKU[sku] = { 
          sales_30d: 0, 
          sales_60d: 0,
          sales_30d_full: 0,
          sales_30d_flex: 0,
          sales_60d_full: 0,
          sales_60d_flex: 0
        };
      }

      // Contadores totales 60 días
      salesBySKU[sku].sales_60d += quantity;

      // Contadores por tipo de fulfillment (60 días)
      if (isFull) {
        salesBySKU[sku].sales_60d_full += quantity;
      } else {
        salesBySKU[sku].sales_60d_flex += quantity;
      }

      // Contadores últimos 30 días
      if (orderDate >= thirtyDaysAgo) {
        salesBySKU[sku].sales_30d += quantity;

        if (isFull) {
          salesBySKU[sku].sales_30d_full += quantity;
        } else {
          salesBySKU[sku].sales_30d_flex += quantity;
        }
      }
    });
  }
});

console.log(`💰 SKUs con ventas: ${Object.keys(salesBySKU).length}`);

// Calcular estadísticas de ventas FULL vs FLEX
let totalSales30dFull = 0;
let totalSales30dFlex = 0;

Object.values(salesBySKU).forEach(sales => {
  totalSales30dFull += sales.sales_30d_full;
  totalSales30dFlex += sales.sales_30d_flex;
});

const totalSales30d = totalSales30dFull + totalSales30dFlex;
const percentFull = totalSales30d > 0 ? (totalSales30dFull / totalSales30d * 100).toFixed(1) : 0;
const percentFlex = totalSales30d > 0 ? (totalSales30dFlex / totalSales30d * 100).toFixed(1) : 0;

console.log(`📊 Ventas últimos 30 días:`);
console.log(`   🏢 FULL (me2): ${totalSales30dFull} unidades (${percentFull}%)`);
console.log(`   📦 FLEX (otros): ${totalSales30dFlex} unidades (${percentFlex}%)`);
console.log(`   📈 TOTAL: ${totalSales30d} unidades`);

// ========================================
// PASO 5: ELIMINAR DUPLICADOS POR SKU
// ========================================
console.log(`📦 Items antes de filtrar duplicados por SKU: ${items.length}`);

const itemsBySKU = {};

items.forEach(item => {
  const data = item.json;
  const sku = extractSKU(data);

  if (!itemsBySKU[sku]) {
    itemsBySKU[sku] = [];
  }

  itemsBySKU[sku].push(item);
});

const uniqueItems = [];
let skusWithDuplicates = 0;
let totalDuplicatesRemoved = 0;

Object.keys(itemsBySKU).forEach(sku => {
  const itemsForSKU = itemsBySKU[sku];

  if (itemsForSKU.length === 1) {
    uniqueItems.push(itemsForSKU[0]);
  } else {
    skusWithDuplicates++;
    totalDuplicatesRemoved += (itemsForSKU.length - 1);

    const sortedItems = itemsForSKU.sort((a, b) => {
      const statusPriority = { 'active': 1, 'paused': 2, 'closed': 3, 'inactive': 4 };
      const priorityA = statusPriority[a.json.status] || 99;
      const priorityB = statusPriority[b.json.status] || 99;
      return priorityA - priorityB;
    });

    const selectedItem = sortedItems[0];
    const mlcIds = itemsForSKU.map(i => i.json.id);
    const stock = selectedItem.json.available_quantity || 0;

    console.log(`🔄 SKU ${sku}: ${itemsForSKU.length} publicaciones duplicadas (MLCs: ${mlcIds.join(', ')}) → Tomando ${selectedItem.json.id} con stock: ${stock}`);

    uniqueItems.push(selectedItem);
  }
});

items = uniqueItems;

console.log(`✅ Items después de filtrar duplicados: ${items.length}`);
console.log(`📊 SKUs con duplicados: ${skusWithDuplicates}`);
console.log(`🗑️ Publicaciones duplicadas removidas: ${totalDuplicatesRemoved}`);

// ========================================
// PASO 6: PROCESAR Y CREAR OUTPUT FINAL
// ========================================
const output = [];
let totalValorizado = 0;
let productosConCosto = 0;
let productosSinCosto = 0;
let totalReposicionNecesaria = 0;

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const data = item.json;
  const sku = extractSKU(data);
  const mlcId = data.id;
  const salesInfo = salesBySKU[sku] || { 
    sales_30d: 0, 
    sales_60d: 0,
    sales_30d_full: 0,
    sales_30d_flex: 0,
    sales_60d_full: 0,
    sales_60d_flex: 0
  };

  if (i % 50 === 0) {
    console.log(`📊 Procesando item ${i + 1}/${items.length}...`);
  }

  // Determinar stock por bodega
  let stockFull = 0;
  let stockFlex = 0;

  if (data.shipping && data.shipping.logistic_type) {
    const logisticType = data.shipping.logistic_type;

    if (logisticType === 'fulfillment') {
      stockFull = data.available_quantity || 0;
    } else if (logisticType === 'cross_docking' || logisticType === 'xd_drop_off') {
      stockFlex = data.available_quantity || 0;
    } else {
      stockFlex = data.available_quantity || 0;
    }
  } else {
    stockFlex = data.available_quantity || 0;
  }

  // Buscar costo
  let costInfo = costsBySKU[sku] || costsByMLC[mlcId] || null;

  let proveedor = 'Sin proveedor';
  let costoUnitario = 0;
  let valorStock = 0;

  if (costInfo) {
    proveedor = costInfo.proveedor;
    costoUnitario = costInfo.costo;
    valorStock = costoUnitario * (data.available_quantity || 0);
    totalValorizado += valorStock;
    productosConCosto++;
  } else {
    productosSinCosto++;
  }

  // CALCULAR NECESIDAD DE REPOSICIÓN
  const stockTotal = data.available_quantity || 0;
  const reposicionNecesaria = Math.max(0, salesInfo.sales_30d - stockTotal);

  // Sugerencia de distribución FULL vs FLEX basada en patrones de venta
  let reposicionFullSugerida = 0;
  let reposicionFlexSugerida = 0;

  if (reposicionNecesaria > 0) {
    totalReposicionNecesaria += reposicionNecesaria;

    // Calcular proporción de ventas FULL vs FLEX
    const totalSalesThisItem = salesInfo.sales_30d;
    if (totalSalesThisItem > 0) {
      const ratioFull = salesInfo.sales_30d_full / totalSalesThisItem;
      const ratioFlex = salesInfo.sales_30d_flex / totalSalesThisItem;

      reposicionFullSugerida = Math.ceil(reposicionNecesaria * ratioFull);
      reposicionFlexSugerida = Math.ceil(reposicionNecesaria * ratioFlex);
    } else {
      // Si no hay ventas, sugerir 50/50
      reposicionFullSugerida = Math.ceil(reposicionNecesaria / 2);
      reposicionFlexSugerida = Math.floor(reposicionNecesaria / 2);
    }
  }

  output.push({
    json: {
      sku: sku,
      item_id: mlcId,
      title: data.title,
      proveedor: proveedor,
      stock_ml: stockTotal,
      stock_full: stockFull,
      stock_flex: stockFlex,
      costo_unitario: costoUnitario,
      valor_stock: valorStock,
      price: data.price,
      sales_30d: salesInfo.sales_30d,
      sales_30d_full: salesInfo.sales_30d_full,
      sales_30d_flex: salesInfo.sales_30d_flex,
      sales_60d: salesInfo.sales_60d,
      sales_60d_full: salesInfo.sales_60d_full,
      sales_60d_flex: salesInfo.sales_60d_flex,
      reposicion_necesaria: reposicionNecesaria,
      reposicion_full_sugerida: reposicionFullSugerida,
      reposicion_flex_sugerida: reposicionFlexSugerida,
      last_update: new Date().toISOString(),
      permalink: data.permalink,
      status: data.status
    }
  });
}

console.log(`✅ Total productos procesados: ${output.length}`);
console.log(`💰 Productos con costo: ${productosConCosto}`);
console.log(`⚠️ Productos SIN costo: ${productosSinCosto}`);
console.log(`💵 Valor total inventario: $${totalValorizado.toLocaleString('es-CL')}`);
console.log(`🔄 Total unidades a reponer: ${totalReposicionNecesaria}`);

// Contar items por estado
const itemsByStatus = {};
output.forEach(item => {
  const status = item.json.status;
  itemsByStatus[status] = (itemsByStatus[status] || 0) + 1;
});

console.log('📊 Items por estado:');
Object.keys(itemsByStatus).forEach(status => {
  console.log(`  - ${status}: ${itemsByStatus[status]} items`);
});

const itemsWithSales = output.filter(item => item.json.sales_30d > 0 || item.json.sales_60d > 0);
console.log(`🎯 Productos con ventas: ${itemsWithSales.length}`);

const itemsNeedingRestock = output.filter(item => item.json.reposicion_necesaria > 0);
console.log(`🔄 Productos que necesitan reposición: ${itemsNeedingRestock.length}`);

// ========================================
// PASO 7: ORDENAR POR PROVEEDOR
// ========================================
console.log('📊 Ordenando output por proveedor...');

output.sort((a, b) => {
  const provA = (a.json.proveedor || 'ZZZ Sin proveedor').toLowerCase();
  const provB = (b.json.proveedor || 'ZZZ Sin proveedor').toLowerCase();
  return provA.localeCompare(provB);
});

// Reorganizar campos para que proveedor sea primero
const reorderedOutput = output.map(item => ({
  json: {
    proveedor: item.json.proveedor,
    sku: item.json.sku,
    item_id: item.json.item_id,
    title: item.json.title,
    stock_ml: item.json.stock_ml,
    stock_full: item.json.stock_full,
    stock_flex: item.json.stock_flex,
    costo_unitario: item.json.costo_unitario,
    valor_stock: item.json.valor_stock,
    price: item.json.price,
    sales_30d: item.json.sales_30d,
    sales_30d_full: item.json.sales_30d_full,
    sales_30d_flex: item.json.sales_30d_flex,
    sales_60d: item.json.sales_60d,
    sales_60d_full: item.json.sales_60d_full,
    sales_60d_flex: item.json.sales_60d_flex,
    reposicion_necesaria: item.json.reposicion_necesaria,
    reposicion_full_sugerida: item.json.reposicion_full_sugerida,
    reposicion_flex_sugerida: item.json.reposicion_flex_sugerida,
    last_update: item.json.last_update,
    permalink: item.json.permalink,
    status: item.json.status
  }
}));

console.log('✅ Output ordenado por proveedor');

return reorderedOutput;

const inventoryData = $input.all();

console.log(`📊 Generando reporte por proveedor de ${inventoryData.length} productos`);

// Agrupar por proveedor
const reportByProvider = {};

inventoryData.forEach(item => {
  const data = item.json;
  const proveedor = data.proveedor || 'Sin proveedor';

  if (!reportByProvider[proveedor]) {
    reportByProvider[proveedor] = {
      proveedor: proveedor,
      cantidad_skus: 0,
      stock_total: 0,
      stock_full: 0,
      stock_flex: 0,
      valor_inventario: 0,
      sales_30d: 0,
      sales_60d: 0,
      valor_ventas_30d: 0,
      valor_ventas_60d: 0
    };
  }

  const provider = reportByProvider[proveedor];

  provider.cantidad_skus++;
  provider.stock_total += data.stock_ml || 0;
  provider.stock_full += data.stock_full || 0;
  provider.stock_flex += data.stock_flex || 0;
  provider.valor_inventario += data.valor_stock || 0;
  provider.sales_30d += data.sales_30d || 0;
  provider.sales_60d += data.sales_60d || 0;

  // Calcular valor de ventas (precio × cantidad vendida)
  if (data.sales_30d > 0) {
    provider.valor_ventas_30d += (data.price || 0) * (data.sales_30d || 0);
  }
  if (data.sales_60d > 0) {
    provider.valor_ventas_60d += (data.price || 0) * (data.sales_60d || 0);
  }
});

// Convertir a array y ordenar por valor de inventario
const report = Object.values(reportByProvider).sort((a, b) => b.valor_inventario - a.valor_inventario);

console.log(`✅ Reporte generado para ${report.length} proveedores`);

// Mostrar resumen
report.slice(0, 5).forEach(p => {
  console.log(`📦 ${p.proveedor}: ${p.cantidad_skus} SKUs, Stock: ${p.stock_total}, Valor: $${p.valor_inventario.toLocaleString('es-CL')}`);
});

// Agregar totales
const totales = {
  proveedor: '🔷 TOTAL GENERAL',
  cantidad_skus: report.reduce((sum, p) => sum + p.cantidad_skus, 0),
  stock_total: report.reduce((sum, p) => sum + p.stock_total, 0),
  stock_full: report.reduce((sum, p) => sum + p.stock_full, 0),
  stock_flex: report.reduce((sum, p) => sum + p.stock_flex, 0),
  valor_inventario: report.reduce((sum, p) => sum + p.valor_inventario, 0),
  sales_30d: report.reduce((sum, p) => sum + p.sales_30d, 0),
  sales_60d: report.reduce((sum, p) => sum + p.sales_60d, 0),
  valor_ventas_30d: report.reduce((sum, p) => sum + p.valor_ventas_30d, 0),
  valor_ventas_60d: report.reduce((sum, p) => sum + p.valor_ventas_60d, 0)
};

report.push(totales);

return report.map(p => ({ json: p }));

const inventoryData = $input.all();

console.log(`📦 Procesando ${inventoryData.length} items para reportes de proveedores`);

// Agrupar por proveedor
const byProvider = {};

inventoryData.forEach(item => {
  const data = item.json;
  const proveedor = data.proveedor || 'Sin proveedor';

  if (!byProvider[proveedor]) {
    byProvider[proveedor] = [];
  }

  byProvider[proveedor].push(data);
});

console.log(`📊 Proveedores encontrados: ${Object.keys(byProvider).length}`);

// Generar estructura de datos para cada proveedor
const providerReports = [];

Object.keys(byProvider).sort().forEach(proveedor => {
  const items = byProvider[proveedor];

  // Filtrar items que necesitan reposición
  const itemsConReposicion = items.filter(i => (i.reposicion_necesaria || 0) > 0);

  if (itemsConReposicion.length === 0) {
    console.log(`⚠️ ${proveedor}: sin items para reponer, saltando...`);
    return;
  }

  console.log(`🏢 ${proveedor}: ${itemsConReposicion.length} items necesitan reposición`);

  // ==== CALCULAR TOTALES ====
  const totales = {
    ventas_full_30d: items.reduce((sum, i) => sum + (i.sales_30d_full || 0), 0),
    ventas_flex_30d: items.reduce((sum, i) => sum + (i.sales_30d_flex || 0), 0),
    stock_bodega: items.reduce((sum, i) => sum + (i.stock_flex || 0), 0),
    stock_full: items.reduce((sum, i) => sum + (i.stock_full || 0), 0),
    reponer_bodega: itemsConReposicion.reduce((sum, i) => sum + (i.reposicion_flex_sugerida || 0), 0),
    reponer_full: itemsConReposicion.reduce((sum, i) => sum + (i.reposicion_full_sugerida || 0), 0),
    total_reponer: itemsConReposicion.reduce((sum, i) => sum + (i.reposicion_necesaria || 0), 0)
  };

  totales.total_ventas_30d = totales.ventas_full_30d + totales.ventas_flex_30d;

  // ==== PREPARAR FILAS PARA GOOGLE SHEETS ====
  const sheetRows = [];

  // FILA 1: ENCABEZADO CON TOTALES
  sheetRows.push({
    row_type: 'HEADER',
    item_id_1: '',
    item_id_2: '',
    proveedor: proveedor,
    sku: '',
    titulo: '',
    ventas_full_30d: totales.ventas_full_30d,
    ventas_flex_30d: totales.ventas_flex_30d,
    stock_bodega: totales.stock_bodega,
    reponer_bodega: totales.reponer_bodega,
