    un_caja_master: '',
    cajas_master: '',
    costo_unitario: ''
  });

  // FILA 2: TOTAL (resumen amarillo)
  sheetRows.push({
    row_type: 'TOTAL',
    item_id_1: '',
    item_id_2: '',
    proveedor: 'TOTAL',
    sku: '',
    titulo: '',
    ventas_full_30d: totales.ventas_full_30d,
    ventas_flex_30d: totales.ventas_flex_30d,
    stock_bodega: totales.stock_bodega,
    reponer_bodega: totales.reponer_bodega,
    stock_full: totales.stock_full,
    reponer_full: totales.reponer_full,
    total_reponer: totales.total_reponer,
    un_caja_master: '',
    cajas_master: totales.total_reponer,
    costo_unitario: ''
  });

  // SECCIÓN: FORMATO ORDEN DE COMPRA
  let totalMontoNeto = 0;
  let totalMontoBruto = 0;
  let totalUnidades = 0;

  itemsConReposicion.forEach(item => {
    const montoNeto = item.costo_unitario * item.reposicion_necesaria;
    const montoBruto = montoNeto * 1.19;

    totalMontoNeto += montoNeto;
    totalMontoBruto += montoBruto;
    totalUnidades += item.reposicion_necesaria;

    sheetRows.push({
      row_type: 'ORDEN_COMPRA',
      codigo_ml: item.item_id,
      sku: item.sku,
      producto: item.title,
      cajas_master: 1, // Placeholder
      unidades: item.reposicion_necesaria,
      costo_unit: Math.round(item.costo_unitario),
      monto_neto: Math.round(montoNeto),
      monto_bruto: Math.round(montoBruto),
      unid_bodega: item.reposicion_flex_sugerida,
      unid_full: item.reposicion_full_sugerida,
      ultima_utilidad: '',
      rentabilidad_pct: ''
    });
  });

  // TOTAL ORDEN DE COMPRA
  sheetRows.push({
    row_type: 'TOTAL_COMPRA',
    sku: 'TOTAL',
    unidades: totalUnidades,
    monto_neto: Math.round(totalMontoNeto),
    monto_bruto: Math.round(totalMontoBruto),
    unid_bodega: totales.reponer_bodega,
    unid_full: totales.reponer_full
  });

  // SECCIÓN: ORDEN DE COMPRA - PROVEEDOR (sin costos)
  itemsConReposicion.forEach(item => {
    sheetRows.push({
      row_type: 'ORDEN_PROVEEDOR',
      sku: item.sku,
      producto: item.title,
      unidades: item.reposicion_necesaria,
      valor_unitario: Math.round(item.costo_unitario),
      subtotal_neto: Math.round(item.costo_unitario * item.reposicion_necesaria),
      subtotal_bruto: Math.round(item.costo_unitario * item.reposicion_necesaria * 1.19)
    });
  });

  sheetRows.push({
    row_type: 'TOTAL_PROVEEDOR',
    sku: 'TOTAL',
    unidades: totalUnidades,
    subtotal_neto: Math.round(totalMontoNeto),
    subtotal_bruto: Math.round(totalMontoBruto)
  });

  // SECCIÓN: LOGÍSTICA - EMPAQUE
  itemsConReposicion.forEach(item => {
    sheetRows.push({
      row_type: 'LOGISTICA',
      sku: item.sku,
      producto: item.title,
      unidades: item.reposicion_necesaria,
      un_caja_master: 1,
      cajas_master: item.reposicion_necesaria
    });
  });

  sheetRows.push({
    row_type: 'TOTAL_LOGISTICA',
    sku: 'TOTAL',
    unidades: totalUnidades,
    cajas_master: totalUnidades
  });

  // SECCIÓN: ANÁLISIS DE RENTABILIDAD
  itemsConReposicion.forEach(item => {
    const margen = item.price - item.costo_unitario;
    const rentabilidad = item.price > 0 ? (margen / item.price * 100) : 0;

    sheetRows.push({
      row_type: 'RENTABILIDAD',
      sku: item.sku,
      producto: item.title,
      costo_unitario: Math.round(item.costo_unitario),
      precio_ultima_venta: Math.round(item.price),
      utilidad: Math.round(margen),
      rentabilidad_pct: rentabilidad.toFixed(2)
    });
  });

  const promedioRentabilidad = itemsConReposicion.reduce((sum, i) => {
    const margen = i.price - i.costo_unitario;
    const rent = i.price > 0 ? (margen / i.price * 100) : 0;
    return sum + rent;
  }, 0) / itemsConReposicion.length;

  sheetRows.push({
    row_type: 'PROMEDIO_RENTABILIDAD',
    sku: 'PROMEDIO',
    costo_unitario: Math.round(totalMontoNeto / totalUnidades),
    utilidad: Math.round(totalMontoNeto / totalUnidades),
    rentabilidad_pct: promedioRentabilidad.toFixed(2)
  });

  providerReports.push({
    json: {
      provider_name: proveedor,
      sheet_data: sheetRows,
      total_items: itemsConReposicion.length,
      inversion_total: Math.round(totalMontoBruto)
    }
  });

  console.log(`   ✅ ${proveedor}: ${sheetRows.length} filas generadas | Inversión: $${Math.round(totalMontoBruto).toLocaleString('es-CL')}`);
});

console.log(`\n📊 Total proveedores con reportes: ${providerReports.length}`);

return providerReports;

