if (itemsNeedingRestock.length === 0) {
  console.log('✅ No hay productos que necesiten reposición');
  return [{
    json: {
      proveedor: '✅ SIN NECESIDAD DE REPOSICIÓN',
      cantidad_skus: 0,
      total_unidades_necesarias: 0,
      unidades_full: 0,
      unidades_flex: 0,
      valor_inversion: 0
    }
  }];
}

// Agrupar por proveedor
const byProvider = {};

itemsNeedingRestock.forEach(item => {
  const data = item.json;
  const proveedor = data.proveedor || 'Sin proveedor';

  if (!byProvider[proveedor]) {
    byProvider[proveedor] = {
      items: [],
      total_unidades: 0,
      total_full: 0,
      total_flex: 0,
      total_inversion: 0
    };
  }

  byProvider[proveedor].items.push(data);
  byProvider[proveedor].total_unidades += data.reposicion_necesaria;
  byProvider[proveedor].total_full += data.reposicion_full_sugerida;
  byProvider[proveedor].total_flex += data.reposicion_flex_sugerida;
  byProvider[proveedor].total_inversion += (data.costo_unitario * data.reposicion_necesaria);
});

// Generar reporte
const report = [];

Object.keys(byProvider).forEach(proveedor => {
  const data = byProvider[proveedor];

  report.push({
    json: {
      proveedor: proveedor,
      cantidad_skus: data.items.length,
      total_unidades_necesarias: data.total_unidades,
      unidades_full: data.total_full,
      unidades_flex: data.total_flex,
      valor_inversion: Math.round(data.total_inversion),
      detalle_skus: data.items.map(i => `${i.sku} (${i.reposicion_necesaria})`).join(', ')
    }
  });
});

